import{_ as e,o as n,c as i,a3 as t}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"14. Education And Training","description":"","frontmatter":{"title":"14. Education And Training","eba":"Health Allied & Managers Admin 2021-2025","topics":["education-pd"]},"headers":[],"relativePath":"ebas/has-managers-admin/managers-admin/education-pd/14-education-and-training.md","filePath":"ebas/has-managers-admin/managers-admin/education-pd/14-education-and-training.md"}'),o={name:"ebas/has-managers-admin/managers-admin/education-pd/14-education-and-training.md"};function r(s,a,d,l,c,p){return n(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="_14-education-and-training" tabindex="-1">14. Education And Training <a class="header-anchor" href="#_14-education-and-training" aria-label="Permalink to &quot;14. Education And Training&quot;">​</a></h1><p>This clause only applies to Managers and Administrative Workers employed by Royal Women’s Hospital or Royal Children’s Hospital.</p><p><strong>14.1</strong> The parties recognise that the health services are regarded as state, national and international centres of excellence within the field of Paediatrics and Adolescence, and Women’s Health and Infertility. As a consequence, the health services assume a vital role in education at a professional and community level.</p><p><strong>14.2</strong> The parties agree that Employees’ education will be supported on a formal and informal basis and that, wherever possible, resources will continue to be provided to support these programs.</p><p><strong>14.3</strong> Relevant and specific in-service education and training will be offered to all Employees on a regular basis comprising a minimum of four hours per month.</p><p>Plain language terms: training, upskilling.</p>',6)])])}const g=e(o,[["render",r]]);export{u as __pageData,g as default};
